async function storageGet(key) {
  try { const r = await window.storage.get(key, true); return r ? JSON.parse(r.value) : null; }
  catch { return null; }
}
async function storageSet(key, val) {
  try { await window.storage.set(key, JSON.stringify(val), true); } catch {}
}

// ── Hook responsive ────────────────────────────────────────────────
function useIsMobile() {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  useEffect(() => {
    const fn = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener("resize", fn);
    return () => window.removeEventListener("resize", fn);
  }, []);
  return isMobile;
}

// ── Hook de reconocimiento de voz ─────────────────────────────────
function useSpeechRecognition({ onResult, onEnd }) {
  const recogRef = useRef(null);
  const [listening, setListening] = useState(false);
  const [supported] = useState(() => !!(window.SpeechRecognition || window.webkitSpeechRecognition));

  const start = useCallback((currentText) => {
    if (!supported) { alert("Tu navegador no soporta reconocimiento de voz.\nUsa Chrome o Safari."); return; }
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    const r = new SR();
    r.lang = "es-CO";
    r.interimResults = true;
    r.continuous = true;
    recogRef.current = r;
    const base = currentText ? currentText + " " : "";
    r.onresult = e => {
      let interim = "", final = "";
      for (let i = e.resultIndex; i < e.results.length; i++) {
        if (e.results[i].isFinal) final += e.results[i][0].transcript;
        else interim += e.results[i][0].transcript;
      }
      onResult(base + final + interim, !!interim);
    };
    r.onerror = () => { setListening(false); };
    r.onend = () => { setListening(false); onEnd && onEnd(); };
    r.start();
    setListening(true);
  }, [supported, onResult, onEnd]);

  const stop = useCallback(() => {
    recogRef.current?.stop();
    setListening(false);
  }, []);

  return { listening, supported, start, stop };
}

// ── Textarea con botón de voz ──────────────────────────────────────
function VoiceTextarea({ value, onChange, placeholder, minHeight = "110px", fieldColor = "#F7F3EE" }) {
  const [interim, setInterim] = useState(false);
  const baseRef = useRef(value);

  const { listening, supported, start, stop } = useSpeechRecognition({
    onResult: (text, isInterim) => {
      setInterim(isInterim);
      onChange(text);
    },
    onEnd: () => setInterim(false),
  });

  const handleMic = () => {
    if (listening) { stop(); return; }
    baseRef.current = value;
    start(value);
  };

  return (
    <div style={{ position: "relative" }}>
      <textarea
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        style={{
          width: "100%", padding: "10px 44px 10px 12px",
          border: listening ? "2px solid #e74c3c" : "1.5px solid #E0D8CE",
          borderRadius: "8px", fontSize: "13px", outline: "none",
          boxSizing: "border-box", fontFamily: "inherit",
          background: interim ? "#FFF5F0" : "#fff",
          minHeight, resize: "vertical", lineHeight: "1.6",
          transition: "border-color 0.2s, background 0.2s"
        }}
      />
      {/* Botón micrófono */}
      {supported && (
        <button
          type="button"
          onClick={handleMic}
          title={listening ? "Detener grabación" : "Dictar con voz"}
          style={{
            position: "absolute", right: "8px", top: "8px",
            width: "30px", height: "30px", borderRadius: "50%",
            border: "none", cursor: "pointer",
            background: listening ? "#e74c3c" : "#1B3A5C",
            color: "#fff", fontSize: "14px",
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: listening ? "0 0 0 4px rgba(231,76,60,0.25)" : "none",
            animation: listening ? "pulse 1.2s ease-in-out infinite" : "none",
          }}
        >
          {listening ? "⏹" : "🎙️"}
        </button>
      )}
      {/* Indicador grabando */}
      {listening && (
        <div style={{
          position: "absolute", bottom: "8px", right: "8px",
          background: "#e74c3c", color: "#fff", fontSize: "10px",
          fontWeight: "700", borderRadius: "10px", padding: "2px 8px",
          letterSpacing: "1px", animation: "pulse 1.2s ease-in-out infinite"
        }}>● GRABANDO</div>
      )}
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </div>
  );
}

// ── Marca de agua ─────────────────────────────────────────────────
function Watermark({ username }) {
  return (
    <div style={{ position:"absolute", inset:0, overflow:"hidden", pointerEvents:"none", zIndex:5 }}>
      {Array.from({length:18}).map((_,i) => (
        <div key={i} style={{
          position:"absolute",
          top:`${(i % 6)*18}%`,
          left:`${Math.floor(i/6)*38 - 10}%`,
          transform:"rotate(-35deg)",
          fontSize:"12px", fontWeight:"700",
          color:"rgba(180,100,20,0.09)",
          whiteSpace:"nowrap", letterSpacing:"2px",
          fontFamily:"Georgia,serif", userSelect:"none"
        }}>DON TELMO • {username.toUpperCase()}</div>
      ))}
    </div>
  );
}

